// operations/traceability/engine/services/TraceTreeService.ts
class TraceTreeService {
  db;
  constructor(db) {
    this.db = db;
  }
  async traceUpstream(lotId) {
    const visited = new Set;
    const buildTree = async (id) => {
      if (visited.has(id))
        return { lot_id: id, circular: true };
      visited.add(id);
      const lotResult = await sql`
        SELECT l.id, l.lot_number, l.lot_type, l.status,
               l.quantity_initial, l.quantity_remaining, l.unit,
               l.best_before_date, l.supplier_lot_ref, l.reception_date,
               i.name as item_name, i.allergens,
               s.name as supplier_name
        FROM trace_lots l
        INNER JOIN trace_items i ON i.id = l.item_id
        LEFT JOIN trace_suppliers s ON s.id = l.supplier_id
        WHERE l.id = ${id}
      `.execute(this.db);
      if (!lotResult.rows.length)
        return { lot_id: id };
      const lot = lotResult.rows[0];
      const parentConsumptions = await sql`
        SELECT c.lot_id, c.quantity_used, c.unit
        FROM trace_production_orders po
        INNER JOIN trace_lot_consumptions c ON c.production_order_id = po.id
        WHERE po.output_lot_id = ${id}
      `.execute(this.db);
      const inputs = await Promise.all(parentConsumptions.rows.map((c) => buildTree(c.lot_id)));
      return {
        lot_id: lot.id,
        lot_number: lot.lot_number,
        lot_type: lot.lot_type,
        status: lot.status,
        quantity_initial: lot.quantity_initial,
        quantity_remaining: lot.quantity_remaining,
        unit: lot.unit,
        best_before_date: lot.best_before_date,
        supplier_lot_ref: lot.supplier_lot_ref,
        reception_date: lot.reception_date,
        item_name: lot.item_name,
        allergens: lot.allergens,
        supplier_name: lot.supplier_name,
        inputs
      };
    };
    return buildTree(lotId);
  }
  async traceDownstream(lotId) {
    const visited = new Set;
    const affectedLots = [];
    const affectedCustomers = [];
    const queue = [lotId];
    while (queue.length > 0) {
      const current = queue.shift();
      if (visited.has(current))
        continue;
      visited.add(current);
      const orders = await sql`
        SELECT po.output_lot_id, po.order_number,
               l.lot_number, l.status, l.quantity_remaining, l.unit,
               i.name as item_name
        FROM trace_lot_consumptions c
        INNER JOIN trace_production_orders po ON po.id = c.production_order_id
        INNER JOIN trace_lots l ON l.id = po.output_lot_id
        INNER JOIN trace_items i ON i.id = l.item_id
        WHERE c.lot_id = ${current}
      `.execute(this.db);
      for (const order of orders.rows) {
        affectedLots.push(order);
        queue.push(order.output_lot_id);
      }
      const dispatches = await sql`
        SELECT id, quantity, unit, customer_id, reference_number, performed_at
        FROM trace_movements
        WHERE lot_id = ${current} AND type = 'dispatch'
      `.execute(this.db);
      affectedCustomers.push(...dispatches.rows.map((d) => ({ lot_id: current, ...d })));
    }
    return {
      origin_lot_id: lotId,
      affected_lots: affectedLots,
      affected_customers: affectedCustomers,
      total_lots_affected: affectedLots.length,
      total_customers_affected: new Set(affectedCustomers.map((c) => c.customer_id).filter(Boolean)).size
    };
  }
  async getLotTimeline(lotId) {
    const rows = await sql`
      SELECT m.id, m.type, m.quantity, m.unit,
             m.reference_type, m.reference_number,
             m.notes, m.performed_at,
             fl.warehouse as from_warehouse,
             tl.warehouse as to_warehouse
      FROM trace_movements m
      LEFT JOIN trace_locations fl ON fl.id = m.from_location_id
      LEFT JOIN trace_locations tl ON tl.id = m.to_location_id
      WHERE m.lot_id = ${lotId}
      ORDER BY m.performed_at ASC
    `.execute(this.db);
    return rows.rows;
  }
}

// operations/traceability/engine/routes/trace.ts
function traceRouter(ctx) {
  const { db } = ctx;
  function reqDb(c) {
    return ctx.reqDb ? ctx.reqDb(c) : c.get("tenantTrx") ?? db;
  }
  const traceTree = new TraceTreeService(db);
  const app = new Hono2;
  app.get("/:lot_id/upstream", async (c) => {
    const lotId = c.req.param("lot_id");
    const exists = await sql`SELECT id FROM trace_lots WHERE id = ${lotId}`.execute(reqDb(c));
    if (!exists.rows.length)
      return c.json({ error: "Lot neg\u0103sit / Lot not found" }, 404);
    const tree = await traceTree.traceUpstream(lotId);
    return c.json({ data: tree });
  });
  app.get("/:lot_id/downstream", async (c) => {
    const lotId = c.req.param("lot_id");
    const exists = await sql`SELECT id FROM trace_lots WHERE id = ${lotId}`.execute(reqDb(c));
    if (!exists.rows.length)
      return c.json({ error: "Lot neg\u0103sit / Lot not found" }, 404);
    const result = await traceTree.traceDownstream(lotId);
    return c.json({ data: result });
  });
  app.get("/:lot_id/timeline", async (c) => {
    const lotId = c.req.param("lot_id");
    const exists = await sql`SELECT id FROM trace_lots WHERE id = ${lotId}`.execute(reqDb(c));
    if (!exists.rows.length)
      return c.json({ error: "Lot neg\u0103sit / Lot not found" }, 404);
    const timeline = await traceTree.getLotTimeline(lotId);
    return c.json({ data: timeline });
  });
  return app;
}

// operations/traceability/engine/services/RecallService.ts
class RecallService {
  db;
  traceTree;
  constructor(db) {
    this.db = db;
    this.traceTree = new TraceTreeService(db);
  }
  async simulateRecall(lotId) {
    const downstream = await this.traceTree.traceDownstream(lotId);
    return {
      is_simulation: true,
      ...downstream,
      recommended_action: this.determineAction(downstream)
    };
  }
  async initiateRecall(params) {
    const downstream = await this.traceTree.traceDownstream(params.lotId);
    const affectedIds = [params.lotId, ...downstream.affected_lots.map((l) => l.output_lot_id)];
    await sql`
      UPDATE trace_lots
      SET status = 'recalled'
      WHERE id = ANY(${affectedIds}::uuid[])
    `.execute(this.db);
    const recallResult = await sql`
      INSERT INTO trace_recalls (lot_id, scope, reason, initiated_by, initiated_at, affected_downstream_lots, status)
      VALUES (
        ${params.lotId},
        ${params.scope},
        ${params.reason},
        ${params.initiatedBy},
        now(),
        ${JSON.stringify(downstream.affected_lots)}::jsonb,
        'active'
      )
      RETURNING *
    `.execute(this.db);
    return recallResult.rows[0];
  }
  async resolveRecall(recallId, resolvedBy, resolutionNotes) {
    const result = await sql`
      UPDATE trace_recalls
      SET status = 'resolved', resolved_by = ${resolvedBy}, resolved_at = now(), resolution_notes = ${resolutionNotes}
      WHERE id = ${recallId} AND status = 'active'
      RETURNING *
    `.execute(this.db);
    if (!result.rows.length)
      throw new Error("Recall neg\u0103sit sau deja rezolvat / Recall not found or already resolved");
    return result.rows[0];
  }
  determineAction(downstream) {
    if (downstream.affected_customers.length > 0)
      return "consumer_recall";
    if (downstream.affected_lots.some((l) => l.status === "available"))
      return "market_withdrawal";
    return "internal";
  }
}

// operations/traceability/engine/routes/recalls.ts
function recallsRouter(ctx) {
  const { db } = ctx;
  function reqDb(c) {
    return ctx.reqDb ? ctx.reqDb(c) : c.get("tenantTrx") ?? db;
  }
  const recallService = new RecallService(db);
  const app = new Hono2;
  app.post("/simulate/:lot_id", async (c) => {
    const lotId = c.req.param("lot_id");
    const exists = await sql`SELECT id FROM trace_lots WHERE id = ${lotId}`.execute(reqDb(c));
    if (!exists.rows.length)
      return c.json({ error: "Lot neg\u0103sit / Lot not found" }, 404);
    const simulation = await recallService.simulateRecall(lotId);
    return c.json({ data: simulation });
  });
  app.post("/initiate", zValidator("json", exports_external.object({
    lot_id: exports_external.string().uuid(),
    reason: exports_external.string().min(10),
    scope: exports_external.enum(["internal", "market_withdrawal", "consumer_recall"])
  })), async (c) => {
    const user = c.get("user");
    const d = c.req.valid("json");
    const exists = await sql`SELECT id FROM trace_lots WHERE id = ${d.lot_id}`.execute(reqDb(c));
    if (!exists.rows.length)
      return c.json({ error: "Lot neg\u0103sit / Lot not found" }, 404);
    const recall = await recallService.initiateRecall({
      lotId: d.lot_id,
      reason: d.reason,
      scope: d.scope,
      initiatedBy: user.id
    });
    return c.json({ data: recall }, 201);
  });
  app.get("/", async (c) => {
    const { status } = c.req.query();
    const rows = await sql`
      SELECT r.id, r.scope, r.reason, r.status, r.initiated_at, r.resolved_at,
             r.affected_downstream_lots,
             l.lot_number, i.name as item_name
      FROM trace_recalls r
      INNER JOIN trace_lots l ON l.id = r.lot_id
      INNER JOIN trace_items i ON i.id = l.item_id
      WHERE (${status ? sql`r.status = ${status}` : sql`TRUE`})
      ORDER BY r.initiated_at DESC
    `.execute(reqDb(c));
    return c.json({ data: rows.rows });
  });
  app.get("/:id", async (c) => {
    const row = await sql`
      SELECT r.*,
             l.lot_number, l.quantity_initial, l.unit,
             i.name as item_name, i.allergens
      FROM trace_recalls r
      INNER JOIN trace_lots l ON l.id = r.lot_id
      INNER JOIN trace_items i ON i.id = l.item_id
      WHERE r.id = ${c.req.param("id")}
    `.execute(reqDb(c));
    if (!row.rows.length)
      return c.json({ error: "Recall neg\u0103sit / Recall not found" }, 404);
    return c.json({ data: row.rows[0] });
  });
  app.patch("/:id/resolve", zValidator("json", exports_external.object({
    resolution_notes: exports_external.string().min(5)
  })), async (c) => {
    const user = c.get("user");
    const { resolution_notes } = c.req.valid("json");
    const id = c.req.param("id");
    const recall = await recallService.resolveRecall(id, user.id, resolution_notes);
    return c.json({ data: recall });
  });
  return app;
}

