// operations/traceability/engine/routes/index.ts
function traceRoutes(ctx) {
  const app = new Hono2;
  app.use("*", async (c, next) => {
    const session = await ctx.auth.api.getSession({ headers: c.req.raw.headers });
    if (!session)
      return c.json({ error: "Unauthorized" }, 401);
    c.set("user", session.user);
    await next();
  });
  app.get("/me", (c) => {
    const user = c.get("user");
    return c.json({ id: user.id, name: user.name, email: user.email });
  });
  app.route("/suppliers", suppliersRouter(ctx));
  app.route("/items", itemsRouter(ctx));
  app.route("/locations", locationsRouter(ctx));
  app.route("/lots", lotsRouter(ctx));
  app.route("/scan", scanRouter(ctx));
  app.route("/production", productionRouter(ctx));
  app.route("/tree", traceRouter(ctx));
  app.route("/recalls", recallsRouter(ctx));
  app.route("/labels", labelsRouter(ctx));
  app.route("/reports", reportsRouter(ctx));
  app.route("/dispatches", dispatchesRouter(ctx));
  return app;
}

// operations/traceability/engine/index.ts
var extension = {
  name: "operations/traceability",
  category: "operations",
  mountStrategy: "subapp",
  getMigrations() {
    return [
      join(import.meta.dir, "migrations/001_initial.sql"),
      join(import.meta.dir, "migrations/002_tenant_rls.sql")
    ];
  },
  async register(app, ctx) {
    app.route("/", traceRoutes(ctx));
    ctx.events.on("record.created", async ({ collection, record: record2, id }) => {
      if (collection !== "zvd_invoices")
        return;
      try {
        const linesResult = await sql`
          SELECT id, description, quantity, unit, metadata
          FROM zvd_invoice_lines
          WHERE invoice_id = ${id}
            AND (metadata->>'lot_id') IS NOT NULL
        `.execute(ctx.db);
        for (const line of linesResult.rows) {
          const lotId = line.metadata?.lot_id;
          if (!lotId)
            continue;
          const lotCheck = await sql`
            SELECT id FROM trace_lots WHERE id = ${lotId} AND status = 'available'
          `.execute(ctx.db);
          if (!lotCheck.rows.length)
            continue;
          await sql`
            INSERT INTO trace_dispatches (
              invoice_id, invoice_number, invoice_line_id,
              customer_id, customer_name,
              lot_id, item_name_from_invoice,
              quantity_invoiced, unit, status
            ) VALUES (
              ${id}, ${record2.number}, ${line.id},
              ${record2.client_id ?? null}, ${record2.client_name},
              ${lotId}, ${line.description},
              ${line.quantity}, ${line.unit ?? "buc"}, 'pending'
            )
            ON CONFLICT DO NOTHING
          `.execute(ctx.db);
        }
      } catch {}
    });
  }
};
var engine_default = extension;
export {
  engine_default as default
};
